 20 private struct ChartSettingsContent: View {
 21     let preferences: UserDefaultsAppPreferences
 22     @Bindable var store: UsageStore
 23 
 24     @State private var pendingDelete: UUID?
 25 
 26     var body: some View {
 27         VStack(alignment: .leading, spacing: 0) {
 28             header
 29             Divider()
 30             chartList
 31         }
 32         .confirmationDialog(
 33             deleteConfirmationTitle,
 34             isPresented: deleteConfirmationBinding,
 35             titleVisibility: .visible
 36         ) {
 37             Button("Delete chart", role: .destructive) {
 38                 if let id = pendingDelete {
 39                     delete(configurationID: id)
 40                 }
 41                 pendingDelete = nil
 42             }
 43             Button("Cancel", role: .cancel) {
 44                 pendingDelete = nil
 45             }
 46         } message: {
 47             Text("This chart will no longer appear in the popover.")
 48         }
 49     }
 50 
 51     private var header: some View {
 52         HStack {
 53             VStack(alignment: .leading, spacing: 3) {
 54                 Text("Charts")
 55                     .font(.headline)
 56                 Text("Configure the charts shown in the history tab.")
 57                     .font(.caption)
 58                     .foregroundStyle(.secondary)
 59             }
 60             Spacer()
 61             Button {
 62                 addConfiguration()
 63             } label: {
 64                 Label("Add", systemImage: "plus")
 65             }
 66         }
 67         .padding(16)
 68     }
 69 
 70     @ViewBuilder
 71     private var chartList: some View {
 72         if preferences.chartConfigurations.isEmpty {
 73             emptyState
 74         } else {
 75             ScrollView {
 76                 VStack(spacing: 0) {
 77                     ForEach(Array(preferences.chartConfigurations.enumerated()), id: \.element.id) { index, _ in
 78                         ChartConfigurationCard(
 79                             preferences: preferences,
 80                             store: store,
 81                             index: index,
 82                             canMoveUp: index > 0,
 83                             canMoveDown: index < preferences.chartConfigurations.count - 1,
 84                             onMoveUp: { move(from: index, to: index - 1) },
 85                             onMoveDown: { move(from: index, to: index + 2) },
 86                             onRequestDelete: { pendingDelete = preferences.chartConfigurations[index].id }
 87                         )
 88                         Divider()
 89                     }
 90                 }
 91                 .padding(.horizontal, 16)
 92             }
 93         }
 94     }
 95 
 96     private var emptyState: some View {
 97         VStack(spacing: 12) {
 98             Spacer(minLength: 24)
 99             Text("No chart configured")
100                 .font(.headline)
101             Text("The history tab will be empty until you add a chart.")
102                 .font(.caption)
103                 .foregroundStyle(.secondary)
104             Button {
105                 addConfiguration()
106             } label: {
107                 Label("Add your first chart", systemImage: "plus")
108             }
109             Spacer(minLength: 24)
110         }
111         .frame(maxWidth: .infinity)
112         .padding(16)
113     }
114 
115     private func addConfiguration() {
116         preferences.chartConfigurations.append(ChartConfigurationsSeeder.defaultConfigurations()[0])
117     }
118 
119     private func delete(configurationID: UUID) {
120         preferences.chartConfigurations.removeAll { $0.id == configurationID }
121     }
122 
123     private func move(from source: Int, to destination: Int) {
124         var configurations = preferences.chartConfigurations
125         guard source >= 0, source < configurations.count else { return }
126         let dest = max(0, min(destination, configurations.count))
127         configurations.move(fromOffsets: IndexSet(integer: source), toOffset: dest)
128         preferences.chartConfigurations = configurations
129     }
130 
131     private var deleteConfirmationBinding: Binding<Bool> {
132         Binding(
133             get: { pendingDelete != nil },
134             set: { if !$0 { pendingDelete = nil } }
135         )
136     }
137 
138     private var deleteConfirmationTitle: String {
139         guard let id = pendingDelete,
140               let configuration = preferences.chartConfigurations.first(where: { $0.id == id }) else {
141             return "Delete chart?"
142         }
143         return "Delete \(configuration.title) chart?"
144     }
145 }
