147 private struct ChartConfigurationCard: View {
148     let preferences: UserDefaultsAppPreferences
149     @Bindable var store: UsageStore
150     let index: Int
151     let canMoveUp: Bool
152     let canMoveDown: Bool
153     let onMoveUp: () -> Void
154     let onMoveDown: () -> Void
155     let onRequestDelete: () -> Void
156 
157     @State private var isExpanded = false
158 
159     private var configurationBinding: Binding<ChartConfiguration>? {
160         guard preferences.chartConfigurations.indices.contains(index) else { return nil }
161         return Binding(
162             get: { preferences.chartConfigurations[index] },
163             set: { preferences.chartConfigurations[index] = $0 }
164         )
165     }
166 
167     var body: some View {
168         if let configurationBinding {
169             DisclosureGroup(isExpanded: $isExpanded) {
170                 ChartConfigurationEditor(
171                     store: store,
172                     configuration: configurationBinding
173                 )
174                 .padding(.top, 8)
175             } label: {
176                 header(for: configurationBinding.wrappedValue)
177             }
178             .padding(.vertical, 4)
179         }
180     }
181 
182     private func header(for configuration: ChartConfiguration) -> some View {
183         HStack(spacing: 8) {
184             VStack(alignment: .leading, spacing: 2) {
185                 Text(configuration.title)
186                     .font(.body)
187                     .lineLimit(1)
188                 Text(summary(for: configuration))
189                     .font(.caption)
190                     .foregroundStyle(.secondary)
191                     .lineLimit(1)
192             }
193             .frame(maxWidth: .infinity, alignment: .leading)
194 
195             HStack(spacing: 4) {
196                 Button(action: onMoveUp) {
197                     Image(systemName: "arrow.up")
198                 }
199                 .buttonStyle(.borderless)
200                 .disabled(!canMoveUp)
201                 .help("Move up")
202 
203                 Button(action: onMoveDown) {
204                     Image(systemName: "arrow.down")
205                 }
206                 .buttonStyle(.borderless)
207                 .disabled(!canMoveDown)
208                 .help("Move down")
209 
210                 Button(action: onRequestDelete) {
211                     Image(systemName: "trash")
212                         .foregroundStyle(.red)
213                 }
214                 .buttonStyle(.borderless)
215                 .help("Delete chart")
216             }
217         }
218     }
219 
220     private func summary(for configuration: ChartConfiguration) -> String {
221         switch configuration.selection {
222         case .allAvailable:
223             return "All available metrics"
224         case .custom(let series):
225             return "\(series.count) custom series"
226         }
227     }
228 }
