230 private struct ChartConfigurationEditor: View {
231     @Bindable var store: UsageStore
232     @Binding var configuration: ChartConfiguration
233 
234     var body: some View {
235         VStack(alignment: .leading, spacing: 12) {
236             HStack {
237                 Text("Name")
238                     .frame(width: 80, alignment: .leading)
239                 TextField("", text: $configuration.title)
240                     .textFieldStyle(.roundedBorder)
241             }
242 
243             Picker("Series", selection: selectionModeBinding) {
244                 Text("All available metrics").tag(ChartSelectionMode.allAvailable)
245                 Text("Custom").tag(ChartSelectionMode.custom)
246             }
247             .pickerStyle(.segmented)
248 
249             if case .custom = configuration.selection {
250                 customSeriesList
251             }
252         }
253     }
254 
255     private var customSeriesList: some View {
256         VStack(alignment: .leading, spacing: 10) {
257             HStack {
258                 Text("Series")
259                     .font(.caption)
260                     .foregroundStyle(.secondary)
261                     .textCase(.uppercase)
262                 Spacer()
263                 Button {
264                     addSeries()
265                 } label: {
266                     Label("Add series", systemImage: "plus")
267                 }
268                 .disabled(availableVendors.isEmpty)
269             }
270 
271             let series = customSeries
272             if series.isEmpty {
273                 Text("No custom series configured")
274                     .font(.caption)
275                     .foregroundStyle(.secondary)
276                     .padding(.vertical, 6)
277             } else {
278                 ForEach(Array(series.enumerated()), id: \.element.id) { index, _ in
279                     ChartSeriesEditor(
280                         store: store,
281                         series: customSeriesBinding(at: index),
282                         onDelete: { deleteSeries(at: index) }
283                     )
284                     .padding(10)
285                     .background(Color(NSColor.controlBackgroundColor), in: RoundedRectangle(cornerRadius: 6))
286                 }
287             }
288         }
289     }
290 
291     private var selectionModeBinding: Binding<ChartSelectionMode> {
292         Binding(
293             get: {
294                 switch configuration.selection {
295                 case .allAvailable: .allAvailable
296                 case .custom: .custom
297                 }
298             },
299             set: { mode in
300                 switch mode {
301                 case .allAvailable:
302                     configuration.selection = .allAvailable
303                     if configuration.title.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
304                         configuration.title = "All available metrics"
305                     }
306                 case .custom:
307                     configuration.selection = .custom(customSeries)
308                 }
309             }
310         )
311     }
312 
313     private var customSeries: [ChartSeriesConfig] {
314         if case .custom(let series) = configuration.selection {
315             return series
316         }
317         return []
318     }
319 
320     private func customSeriesBinding(at index: Int) -> Binding<ChartSeriesConfig> {
321         Binding(
322             get: { customSeries[index] },
323             set: { newValue in
324                 var series = customSeries
325                 guard series.indices.contains(index) else { return }
326                 series[index] = newValue
327                 configuration.selection = .custom(series)
328             }
329         )
330     }
331 
332     private func addSeries() {
333         guard let vendor = availableVendors.first else { return }
334         let metricName = firstAvailableMetricName(for: vendor, account: .currentlyActive) ?? ""
335         var series = customSeries
336         series.append(
337             ChartSeriesConfig(
338                 vendor: vendor,
339                 account: .currentlyActive,
340                 metricName: metricName,
341                 style: ChartSeriesStyle(
342                     color: ChartSeriesColor.allCases[series.count % ChartSeriesColor.allCases.count],
343                     lineStyle: .solid
344                 )
345             )
346         )
347         configuration.selection = .custom(series)
348     }
349 
350     private func deleteSeries(at index: Int) {
351         var series = customSeries
352         guard series.indices.contains(index) else { return }
353         series.remove(at: index)
354         configuration.selection = .custom(series)
355     }
356 
357     private var availableVendors: [Vendor] {
358         Array(Set(store.entries.map(\.vendor))).sorted { $0.rawValue < $1.rawValue }
359     }
360 
361     private func firstAvailableMetricName(for vendor: Vendor, account: AccountSelection) -> String? {
362         let vendorEntries = store.entries.filter { $0.vendor == vendor }
363         let entry: VendorUsageEntry?
364         switch account {
365         case .currentlyActive:
366             entry = vendorEntries.first(where: { $0.isActive })
367         case .specific(let email):
368             entry = vendorEntries.first(where: { $0.account == email })
369         }
370         return entry?.metrics.compactMap(SegmentEditingHelpers.metricName).first
371     }
372 }
373 
374 private struct ChartSeriesEditor: View {
375     @Bindable var store: UsageStore
376     @Binding var series: ChartSeriesConfig
377     let onDelete: () -> Void
378 
379     var body: some View {
380         VStack(alignment: .leading, spacing: 10) {
381             HStack {
382                 Text("Series name")
383                     .frame(width: 80, alignment: .leading)
384                 TextField("", text: seriesLabelBinding)
385                     .textFieldStyle(.roundedBorder)
386             }
387 
388             HStack(alignment: .top) {
389                 MetricSelectionEditor(
390                     store: store,
391                     vendor: $series.vendor,
392                     account: $series.account,
393                     metricName: $series.metricName
394                 )
395 
396                 Spacer(minLength: 8)
397 
398                 Button(action: onDelete) {
399                     Image(systemName: "trash")
400                         .foregroundStyle(.red)
401                 }
402                 .buttonStyle(.borderless)
403                 .help("Delete series")
404             }
405 
406             HStack {
407                 Text("Style")
408                     .frame(width: 80, alignment: .leading)
409 
410                 Picker("Color", selection: $series.style.color) {
411                     ForEach(ChartSeriesColor.allCases) { color in
412                         HStack(spacing: 6) {
413                             Circle()
414                                 .fill(color.swiftUIColor)
415                                 .frame(width: 10, height: 10)
416                             Text(color.displayName)
417                         }
418                         .tag(color)
419                     }
420                 }
421                 .labelsHidden()
422                 .frame(width: 120)
423 
424                 Picker("Line", selection: $series.style.lineStyle) {
425                     ForEach(ChartLineStyle.allCases) { lineStyle in
426                         Text(lineStyle.displayName).tag(lineStyle)
427                     }
428                 }
429                 .labelsHidden()
430                 .frame(width: 120)
431             }
432         }
433     }
434 
435     private var seriesLabelBinding: Binding<String> {
436         Binding(
437             get: {
438                 let customLabel = series.label.trimmingCharacters(in: .whitespacesAndNewlines)
439                 return customLabel.isEmpty ? defaultSeriesLabel : series.label
440             },
441             set: { series.label = $0 }
442         )
443     }
444 
445     private var defaultSeriesLabel: String {
446         let accountLabel: String
447         switch series.account {
448         case .currentlyActive:
449             if let entry = store.entries.first(where: { $0.vendor == series.vendor && $0.isActive }) {
450                 accountLabel = entry.account.rawValue
451             } else {
452                 accountLabel = "currently active"
453             }
454         case .specific(let email):
455             accountLabel = email.rawValue
456         }
457         return "\(series.vendor.rawValue) / \(accountLabel) / \(series.metricName)"
458     }
459 }
460 
461 private enum ChartSelectionMode: Hashable {
462     case allAvailable
463     case custom
464 }

